    const dbNames = new Set(allDbItems.map(i => i.name.toLowerCase()));
    const uniqueSamples = SEED_TESTS.filter(s => !dbNames.has(s.name.toLowerCase()));

    return [...items, ...uniqueSamples];
  } catch (err) {
    console.error("Error fetching tests:", err);
    return SEED_TESTS;
  }
}

