"import { doc, getDoc, setDoc } from "firebase/firestore";
import { db, isFirebaseConfigured, withTimeout } from "./firebase";

export interface Announcement {
  text: string;
  active: boolean;
  link: string;
}

const DEFAULT_ANNOUNCEMENT: Announcement = {
  text: "Welcome to Aradhiya Scans & Lab. Premium diagnostics at your convenience in Chidambaram.",
  active: false,
  link: "",
};

export async function fetchAnnouncement(): Promise<Announcement> {
  if (!isFirebaseConfigured || !db) return DEFAULT_ANNOUNCEMENT;
  try {
    const docRef = doc(db, "announcements", "global_announcement");
    const snap = await withTimeout(getDoc(docRef));
    if (snap.exists()) {
      return snap.data() as Announcement;
    }
    return DEFAULT_ANNOUNCEMENT;
  } catch (err) {
    console.error("Error fetching announcement:", err);
    return DEFAULT_ANNOUNCEMENT;
  }
}

export async function updateAnnouncement(data: Announcement): Promise<void> {
  if (!db) throw new Error("Firebase not configured");
  const docRef = doc(db, "announcements", "global_announcement");
  return withTimeout(setDoc(docRef, data));
}
