const COOKIE_NAME = "patient_session";

export async function POST(request: Request) {
  try {
    const { phone, pin } = await request.json();
    if (!phone || !pin) {
      return new Response(JSON.stringify({ error: "Phone number and PIN are required." }), {
        status: 400,
        headers: { "Content-Type": "application/json" }
      });
    }

    const isValid = await verifyPatientPin(phone, pin);
    if (!isValid) {
      return new Response(JSON.stringify({ error: "Invalid phone number or PIN." }), {
        status: 401,
        headers: { "Content-Type": "application/json" }
      });
    }

    const cleanPhone = phone.replace(/\D/g, "");
    const expiresAt = Date.now() + 60 * 60 * 1000; // 1 hour session
    const token = await signSession({ phone: cleanPhone, expiresAt }, SESSION_SECRET);

    const cookieStore = await cookies();
    cookieStore.set(COOKIE_NAME, token, {
      path: "/",
      httpOnly: true,
      sameSite: "strict",
      secure: process.env.NODE_ENV === "production",
      maxAge: 3600 // 1 hour
    });

    return new Response(JSON.stringify({ success: true, phone: cleanPhone }), {
      status: 200,
      headers: { "Content-Type": "application/json" }
    });
  } catch (err: any) {
    console.error("[verify-pin API] Error:", err.message || err);
    return new Response(JSON.stringify({ error: err.message || "Authentication failed." }), {
      status: 500,
      headers: { "Content-Type": "application/json" }
    });
  }
}
