"'use client';

import React, { useState, useEffect } from "react";
import Link from "next/link";
import { Megaphone, X } from "lucide-react";

export default function AnnouncementBar() {
  const [announcement, setAnnouncement] = useState<{ text: string; active: boolean; link: string } | null>(null);
  const [isVisible, setIsVisible] = useState(true);

  useEffect(() => {
    async function loadAnnouncement() {
      try {
        const res = await fetch("/api/announcement");
        if (res.ok) {
          const data = await res.json();
          setAnnouncement(data);
        }
      } catch (err) {
        console.error("Failed to load global announcement:", err);
      }
    }
    loadAnnouncement();
  }, []);

  if (!announcement || !announcement.active || !isVisible) return null;

  const content = (
    <div className="flex items-center justify-between gap-x-6 bg-[#052327] px-6 py-2.5 sm:px-8">
      <div className="flex items-center gap-x-2 text-xs text-brand-cream mx-auto font-sans font-semibold uppercase tracking-wider text-center">
        <Megaphone className="h-4 w-4 shrink-0 text-brand-gold animate-bounce" />
        <span>{announcement.text}</span>
      </div>
      <button
        onClick={() => setIsVisible(false)}
        className="p-1 rounded-full text-brand-cream/60 hover:text-brand-cream hover:bg-white/5 transition cursor-pointer"
        aria-label="Dismiss banner"
      >
        <X className="h-4 w-4" />
      </button>
    </div>
  );

  if (announcement.link) {
    return (
      <Link href={announcement.link} className="block hover:opacity-95 transition-opacity">
        {content}
      </Link>
    );
  }

  return content;
}
